  function newMatchRound(render = true) { const chosen = shuffle(getLesson().vocabulary).slice(0, 4); matchRound = chosen; selectedEnglish = null; $('matchEnglish').innerHTML = shuffle(chosen).map(([en]) => `<button class="match-item" data-match-en="${escapeHtml(en)}">${escapeHtml(en)}</button>`).join(''); $('matchPortuguese').innerHTML = shuffle(chosen).map(([en, pt]) => `<button class="match-item" data-match-pt="${escapeHtml(en)}">${escapeHtml(pt)}</button>`).join(''); $('matchFeedback').textContent = 'Escolha uma palavra em inglês e depois o significado.'; if (render) renderDashboard(); }
  function chooseEnglish(button) { if (button.classList.contains('matched')) return; document.querySelectorAll('[data-match-en]').forEach(b => b.classList.remove('selected')); button.classList.add('selected'); selectedEnglish = button.dataset.matchEn; speak(selectedEnglish); }
  function choosePortuguese(button) { if (!selectedEnglish) return $('matchFeedback').textContent = 'Primeiro escolha uma palavra em inglês.'; const english = [...document.querySelectorAll('[data-match-en]')].find(b => b.dataset.matchEn === selectedEnglish); if (button.dataset.matchPt === selectedEnglish) { button.classList.add('matched'); english.classList.add('matched'); english.classList.remove('selected'); selectedEnglish = null; $('matchFeedback').textContent = 'Correto!'; addGamePoints(5, 'Ligação correta'); } else { $('matchFeedback').textContent = 'Ainda não. Ouça a palavra e tente outro significado.'; addReviewWord(selectedEnglish); saveState(false); } }
  function newSentenceRound(render = true) { sentenceRound = sentenceChallenges[(state.day * 3 + Math.floor(Math.random() * sentenceChallenges.length)) % sentenceChallenges.length]; sentenceSelected = []; $('sentenceHintText').textContent = `Objetivo da frase: ${sentenceRound.pt}`; $('sentenceBank').innerHTML = shuffle(sentenceRound.words.map((word, index) => ({ word, index }))).map(x => `<button class="word-chip" data-sentence-word="${escapeHtml(x.word)}">${escapeHtml(x.word)}</button>`).join(''); renderSentenceBuild(); $('sentenceFeedback').textContent = ''; if (render) renderDashboard(); }
  function selectSentenceWord(button) { if (button.classList.contains('used')) return; sentenceSelected.push(button.dataset.sentenceWord); button.classList.add('used'); renderSentenceBuild(); }
  function renderSentenceBuild() { $('sentenceBuild').textContent = sentenceSelected.length ? sentenceSelected.join(' ') : 'Clique nas palavras na ordem correta.'; }
  function undoSentence() { if (!sentenceSelected.length) return; const last = sentenceSelected.pop(); const candidates = [...document.querySelectorAll('[data-sentence-word]')].filter(b => b.dataset.sentenceWord === last && b.classList.contains('used')); candidates[candidates.length - 1]?.classList.remove('used'); renderSentenceBuild(); }
  function checkSentence() { const built = sentenceSelected.join(' ').replace(/\s+([.,!?])/g, '$1'); if (normalize(built) === normalize(sentenceRound.answer)) { $('sentenceFeedback').textContent = 'Perfeito. A ordem está correta.'; speak(sentenceRound.answer); addGamePoints(10, 'Frase montada'); } else { $('sentenceFeedback').textContent = `Ainda não. Observe sujeito, verbo e complemento. Você montou: “${built}”`; addError('Ordem das palavras', built, sentenceRound.answer); saveState(false); } }
  function newListeningRound(render = true) { listeningRound = listeningChallenges[(state.day * 2 + Math.floor(Math.random() * listeningChallenges.length)) % listeningChallenges.length]; $('listeningOptions').innerHTML = shuffle(listeningRound.options).map(option => `<button class="listening-option" data-listening-option="${escapeHtml(option)}">${escapeHtml(option)}</button>`).join(''); $('listeningFeedback').textContent = 'Clique no áudio e escute quantas vezes precisar.'; if (render) renderDashboard(); }
  function answerListening(button) { document.querySelectorAll('[data-listening-option]').forEach(b => b.disabled = true); if (button.dataset.listeningOption === listeningRound.correct) { button.classList.add('correct'); $('listeningFeedback').textContent = 'Correto. Você entendeu a ideia principal.'; state.skills.listening = clamp(state.skills.listening + 2, 0, 100); addGamePoints(10, 'Escuta correta'); } else { button.classList.add('wrong'); [...document.querySelectorAll('[data-listening-option]')].find(b => b.dataset.listeningOption === listeningRound.correct)?.classList.add('correct'); $('listeningFeedback').textContent = 'Ouça novamente comparando com a opção correta.'; addError('Compreensão auditiva', button.dataset.listeningOption, listeningRound.correct); saveState(false); } }
  function newSpeedRound(start = true) { const prompts = [getLesson().scenario, 'Tell me about yourself in one sentence.', 'What is the main risk?', 'What are the next steps?', 'Why do you recommend this option?']; speedPrompt = prompts[Math.floor(Math.random() * prompts.length)]; $('speedPrompt').textContent = speedPrompt; $('speedAnswer').value = ''; $('speedFeedback').textContent = ''; speedSeconds = 20; $('speedTimer').textContent = speedSeconds; clearInterval(speedTimerId); if (start) speedTimerId = setInterval(() => { speedSeconds--; $('speedTimer').textContent = speedSeconds; if (speedSeconds <= 0) { clearInterval(speedTimerId); $('speedFeedback').textContent = 'Tempo encerrado. Tente novamente organizando uma frase simples.'; } }, 1000); }
  function checkSpeed() { const answer = $('speedAnswer').value.trim(); clearInterval(speedTimerId); if (answer.split(/\s+/).length >= 7) { $('speedFeedback').textContent = 'Boa resposta sob pressão.'; addGamePoints(12, 'Resposta rápida'); } else $('speedFeedback').textContent = 'Tente usar pelo menos 7 palavras em uma frase completa.'; }

  function renderAssessments() {
    const milestones = [30, 60, 90, 120, 150, 180]; const next = milestones.find(m => !state.assessments[m]); $('assessmentDue').textContent = next ? `Próxima: dia ${next}` : 'Todas concluídas';
    $('assessmentCards').innerHTML = milestones.map((m, i) => { const result = state.assessments[m], available = state.day >= m || result; return `<article class="card assessment-card ${available ? '' : 'locked'}"><div class="eyebrow">MÊS ${i + 1} • DIA ${m}</div><h3>${assessmentTemplates[i].prompt}</h3><p>${result ? result.feedback || 'Avaliação concluída.' : available ? 'A avaliação está disponível.' : `Disponível ao chegar ao dia ${m}.`}</p>${result ? `<div class="score">${result.score}%</div>` : `<button class="${available ? 'primary' : 'secondary'}" data-start-assessment="${m}" ${available ? '' : 'disabled'}>${available ? 'Iniciar avaliação' : 'Bloqueada'}</button>`}</article>`; }).join('');
  }
  function startAssessment(milestone) { assessmentMilestone = Number(milestone); const template = assessmentTemplates[[30, 60, 90, 120, 150, 180].indexOf(assessmentMilestone)]; $('assessmentRunner').classList.remove('hidden'); $('assessmentLabel').textContent = `AVALIAÇÃO DO DIA ${assessmentMilestone}`; $('assessmentPrompt').textContent = template.prompt; $('assessmentAnswer').value = ''; $('assessmentFeedback').innerHTML = '<div class="grace-mini">G</div><p>Produza uma resposta completa. Você pode escrever ou falar.</p>'; $('assessmentRunner').scrollIntoView({ behavior: 'smooth' }); }
